<template>
	<view class="normal-login-container">
		<view class="logo-content align-center justify-center flex">
			<image style="width: 200rpx;height: 200rpx;" :src="globalConfig.appInfo.logo" mode="widthFix">
			</image>
			
		</view>
		<view style="display: flex;align-items: center;justify-content: center;font-size: 21px;">
			<text class="title">欢迎使用{{globalConfig.appInfo.name}}系统</text>
		</view>
		
		<view class="login-form-content" v-if="needLogin == true">
			<view class="input-item flex align-center">
				<uni-icons class="icon" type="person" color="#3498db" size="30"></uni-icons>
				<input v-model="loginForm.username" class="input" type="text" placeholder="请输入账号" maxlength="30" />
			</view>
			<view class="input-item flex align-center">
				<uni-icons class="icon" type="locked" color="#3498db" size="30"></uni-icons>
				<input v-model="loginForm.password" type="password" password="true" class="input" placeholder="请输入密码" maxlength="20" />
			</view>
			<view class="input-item flex align-center" style="width: 60%;margin: 0px;" v-if="captchaEnabled">
				<uni-icons class="icon" type="chat" color="#3498db" size="30"></uni-icons>
				<input v-model="loginForm.code" type="number" class="input" placeholder="请输入验证码" maxlength="4" />
				<view class="login-code">
					<image :src="codeUrl" @click="getCode" class="login-code-img"></image>
				</view>
			</view>
			<view class="action-btn">
				<button @click="handleLogin" class="login-btn cu-btn block bg-blue lg round">登录</button>
			</view>
			<!-- <view class="reg text-center" v-if="register">
				<text class="text-grey1">没有账号？</text>
				<text @click="handleUserRegister" class="text-blue">立即注册</text>
			</view> -->
			<view class="xieyi text-center">
				<text class="text-grey1">登录即代表同意</text>
				<text @click="handleUserAgrement" class="text-blue">《用户协议》</text>
				<text @click="handlePrivacy" class="text-blue">《隐私协议》</text>
			</view>
			<!-- <view class="action-btn">
				<button @click="handleReg" class="login-btn cu-btn block bg-blue lg round">注册体验账户</button>
			</view> -->
		</view>

	</view>
</template>

<script setup>
	import {
		ref,
		getCurrentInstance,
	} from 'vue'
	import {
		onLoad,
		onShow,
	} from '@dcloudio/uni-app'
	import {
		getCodeImg,
		getInfo
	} from '@/api/login'
	import {
		getToken
	} from '@/utils/auth';

	import useUserStore from '@/store/modules/user'

	const userStore = useUserStore();

	const {
		proxy
	} = getCurrentInstance();

	const statusBarHeight = uni.getSystemInfoSync().statusBarHeight ||
		0 // 状态栏高度‌:ml-citation{ref="4,7" data="citationList"}
	const navHeight = 250 // 导航栏标准高度（单位px）

	const codeUrl = ref('');
	const captchaEnabled = ref(true);
	const register = ref(true);
	const globalConfig = ref(getApp().globalData.config);
	const loginForm = ref({
		username: "",
		password: "",
		code: "",
		uuid: ''
	});
	const needLogin = ref(false)
	onShow(()=>{
		if (getToken() != '') {
			needLogin.value=false;
		} else {
			needLogin.value=true;
		}
	})
	onLoad(() => {
		if (getToken() != '') {
			getInfo().then(res => {
				uni.reLaunch({
					url: '/pages/home/index'
				})
			}).catch(err => {
				userStore.cleanUserInfo();
				uni.clearStorageSync();
				needLogin.value=true;
			})
		} else {
			needLogin.value=true;
		}
	})

	// 用户注册
	const handleUserRegister = () => {
		// proxy.$tab.redirectTo(`/pages/register`)
	}
	// 隐私协议
	const handlePrivacy = () => {
		let site = globalConfig.value.appInfo.agreements[0]
		proxy.$tab.navigateTo(`/pages/common/webview/index?title=${site.title}&url=${site.url}`)
	}
	// 用户协议
	const handleUserAgrement = () => {
		let site = globalConfig.value.appInfo.agreements[1]
		proxy.$tab.navigateTo(`/pages/common/webview/index?title=${site.title}&url=${site.url}`)
	}
	// 获取图形验证码
	const getCode = () => {
		getCodeImg().then(res => {
			captchaEnabled.value = res.captchaEnabled === undefined ? true : res.captchaEnabled
			if (captchaEnabled.value) {
				codeUrl.value = 'data:image/gif;base64,' + res.img
				loginForm.value.uuid = res.uuid
			}
		})
	}
	const handleReg = async () => {
		uni.navigateTo({
			url:'/pages/register'
		})
	}
	// 登录方法
	const handleLogin = async () => {
		if (loginForm.value.username === "") {
			proxy.$modal.msgError("请输入您的账号")
		} else if (loginForm.value.password === "") {
			proxy.$modal.msgError("请输入您的密码")
		} else if (loginForm.value.code === "" && captchaEnabled.value) {
			proxy.$modal.msgError("请输入验证码")
		} else {

			proxy.$modal.loading("登录中，请耐心等待...")
			pwdLogin()
		}
	}
	// 密码登录
	const pwdLogin = async () => {
		userStore.login(loginForm.value).then(() => {
			proxy.$modal.closeLoading()
			loginSuccess()
		}).catch(() => {
			proxy.$modal.closeLoading()
			if (captchaEnabled.value) {
				getCode()
			}
		})
	}
	// 登录成功后，处理函数
	const loginSuccess = async (result) => {
		// 设置用户信息
		await userStore.getInfo().then(res => {
			uni.reLaunch({
				url: '/pages/home/index'
			})
		})
	}
	getCode();
</script>

